  val m = grid.length
  val n = grid(0).length
  val INF = Long.MaxValue

  val teleportable = Array.ofDim[Array[(Int, Int)]](m, n)
  for (i <- 0 until m) {
    for (j <- 0 until n) {
      teleportable(i)(j) = (for {
        x <- 0 until m
        y <- 0 until n
        if grid(x)(y) <= grid(i)(j)
      } yield (x, y)).toArray
    }
  }

  val dist = Array.ofDim[Long](m, n, k.toInt + 1)
  for (i <- 0 until m) {
    for (j <- 0 until n) {
      for (t <- 0 until k.toInt + 1) {
        dist(i)(j)(t) = INF
      }
    }
  }
  dist(0)(0)(0) = 0L

  val pq = PriorityQueue[(Long, Int, Int, Int)]()
  pq += (0L, 0, 0, 0)

  while (pq.nonEmpty) {
    val (cost, x, y, t) = pq.dequeue()
    if (x == m - 1 && y == n - 1) return cost
    if (cost > dist(x)(y)(t)) continue

    val directions = List((0, 1), (1, 0))
    for ((dx, dy) <- directions) {
      val nx = x + dx
      val ny = y + dy
      if (nx < m && ny < n) {
        val newCost = cost + grid(nx)(ny)
        if (newCost < dist(nx)(ny)(t)) {
          dist(nx)(ny)(t) = newCost
          pq += (newCost, nx, ny, t)
        }
      }
    }

    for ((tx, ty) <- teleportable(x)(y)) {
      if (t < k.toInt) {
        val newT = t + 1
        if (cost < dist(tx)(ty)(newT)) {
          dist(tx)(ty)(newT) = cost
          pq += (cost, tx, ty, newT)
        }
      }
    }
  }

  INF
}
